import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Theme Customizations","description":"Spinoko Theme Customizations","frontmatter":{"title":"Theme Customizations","description":"Spinoko Theme Customizations","weight":150,"extra":{"order":150},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/customizations"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/customizations"}],["meta",{"property":"og:title","content":"Theme Customizations"}],["meta",{"property":"og:description","content":"Spinoko Theme Customizations"}],["meta",{"name":"twitter:title","content":"Theme Customizations"}],["meta",{"name":"twitter:description","content":"Spinoko Theme Customizations"}]]},"headers":[],"relativePath":"docs/spinoko/customizations.md","filePath":"docs/spinoko/customizations.md"}'),s={name:"docs/spinoko/customizations.md"};function n(r,e,c,l,d,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="theme-customizations" tabindex="-1">Theme Customizations <a class="header-anchor" href="#theme-customizations" aria-label="Permalink to &quot;Theme Customizations&quot;">â€‹</a></h1><p>Theme customizations are made through native WordPress Customizer. In admin dashboard visit <strong>Appearance</strong> â†’ <strong>Customize</strong> select the options group you want to customize and make the required changes.</p><h3 id="customizer-options" tabindex="-1">Customizer Options <a class="header-anchor" href="#customizer-options" aria-label="Permalink to &quot;Customizer Options&quot;">â€‹</a></h3><p>Below is the main WordPress Customizer view showing all the options you can customize. In continuation you can find explanations and screenshots of all the sections.</p><p>Select the options you want to customize and apply your changes, the preview will reflect your changes automatically. Once you&#39;re happy with the results, click the &quot;Publish&quot; button to save the changes.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer.jpg" alt="Theme Customizations"></p><h3 id="site-identity" tabindex="-1">Site Identity <a class="header-anchor" href="#site-identity" aria-label="Permalink to &quot;Site Identity&quot;">â€‹</a></h3><p>As usual, set your site title and tagline, upload a custom logo and a favicon. If you have a really wide logo, you can hide the site title from header for better appearance.</p><h3 id="colors" tabindex="-1">Colors <a class="header-anchor" href="#colors" aria-label="Permalink to &quot;Colors&quot;">â€‹</a></h3><p>Spinoko has a lot of colors, there are <strong>21 carefully selected colors</strong> that are used all over the theme. You can adjust them to your liking and use your own color pallettes or the one that comes by default.</p><p>In case you want to restore them, here&#39;s a list of <a href="/docs/spinoko/how-to#how-to-restore-default-theme-colors">default colors</a>.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-colors.png" alt="Theme Customizations"></p><h3 id="styles" tabindex="-1">Styles <a class="header-anchor" href="#styles" aria-label="Permalink to &quot;Styles&quot;">â€‹</a></h3><p>Adjust global theme styles here and they will change the look and feel of your website.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-styles.png" alt="Theme Customizations"></p><h3 id="fonts" tabindex="-1">Fonts <a class="header-anchor" href="#fonts" aria-label="Permalink to &quot;Fonts&quot;">â€‹</a></h3><p>Select the font family and base font size for your website. Language specific font families (such as Arabic, Chinese, etc.) are also included.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-fonts.png" alt="Theme Customizations"></p><h3 id="menus" tabindex="-1">Menus <a class="header-anchor" href="#menus" aria-label="Permalink to &quot;Menus&quot;">â€‹</a></h3><p>Spinoko has 2 navigation menu locations - <strong>Header</strong> and <strong>Footer</strong>. Create menus and assign locations here.</p><h3 id="widgets" tabindex="-1">Widgets <a class="header-anchor" href="#widgets" aria-label="Permalink to &quot;Widgets&quot;">â€‹</a></h3><p>Spinoko has no sidebars, the only widget area is in footer - Footer Widgets. You can add widgets to footer and they&#39;ll be displayed in a 3 column grid section. Or you can leave the widget area empty.</p><h3 id="homepage-settings" tabindex="-1">Homepage Settings <a class="header-anchor" href="#homepage-settings" aria-label="Permalink to &quot;Homepage Settings&quot;">â€‹</a></h3><p>You can choose what&#39;s displayed on the homepage of your site. It can be posts/blog page, or a static page. To set a static homepage, you first need to create two Pages. One will become the homepage, and the other will be where your posts are displayed.</p><h3 id="additional-css" tabindex="-1">Additional CSS <a class="header-anchor" href="#additional-css" aria-label="Permalink to &quot;Additional CSS&quot;">â€‹</a></h3><p>If you need to make minor changes to the theme (or plugins) styles, you can do so in <strong>Additional CSS</strong> section.</p><h3 id="additional-scripts" tabindex="-1">Additional Scripts <a class="header-anchor" href="#additional-scripts" aria-label="Permalink to &quot;Additional Scripts&quot;">â€‹</a></h3><p>If you need to embed some scripts to your page, you can do it in <strong>Additional Scripts</strong> section. Here you have 2 locations:</p><ul><li>Header scripts - that will go into the head of the page</li><li>Footer scripts - that will go into the footer part</li></ul><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-scripts.png" alt="Theme Customizations"></p><ul><li>Add scripts only if they are necessary.</li><li>You need to include the <code>&lt;script&gt; ... &lt;/script&gt;</code> tags</li></ul><h3 id="casino-review-options" tabindex="-1">Casino Review Options <a class="header-anchor" href="#casino-review-options" aria-label="Permalink to &quot;Casino Review Options&quot;">â€‹</a></h3><p>All casino review options are here, you can set your affiliate links <code>rel</code> and <code>target</code> attributes, choose review design options, terms and conditions settings, etc.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-reviews.png" alt="Theme Customizations"></p><h3 id="game-review-options" tabindex="-1">Game Review Options <a class="header-anchor" href="#game-review-options" aria-label="Permalink to &quot;Game Review Options&quot;">â€‹</a></h3><p>All game review options can be customized here. You can choose whether to enable game review/ratings snippet for rich results or not, choose it&#39;s author (person or organization). You can also hide sections on game review page that display a casino called where to play.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-game-reviews.png" alt="Theme Customizations"></p><h3 id="page-options" tabindex="-1">Page Options <a class="header-anchor" href="#page-options" aria-label="Permalink to &quot;Page Options&quot;">â€‹</a></h3><p>You can adjust here different options regarding different types of pages.</p><p><strong>Archive pages</strong>: You can set a template for archive pages such as category, tag, author pages, as well as choose a style and word count to display single posts on the mentioned pages.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-pages.png" alt="Theme Customizations"></p><h3 id="header-notifications" tabindex="-1">Header Notifications <a class="header-anchor" href="#header-notifications" aria-label="Permalink to &quot;Header Notifications&quot;">â€‹</a></h3><p>Check out more details about notifications <a href="/docs/spinoko/notifications">here</a>.</p><h3 id="strings" tabindex="-1">Strings <a class="header-anchor" href="#strings" aria-label="Permalink to &quot;Strings&quot;">â€‹</a></h3><p>There are different strings such as button or review link anchor texts, headings and labels, etc. that you may want to change. You can find all of them in <strong>Strings</strong> section.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-strings.png" alt="Theme Customizations"></p><h3 id="miscellaneous-options" tabindex="-1">Miscellaneous Options <a class="header-anchor" href="#miscellaneous-options" aria-label="Permalink to &quot;Miscellaneous Options&quot;">â€‹</a></h3><p>This is a section for (surprise đź¤Ż) miscellaneous options. Here you can enable/disable footer gambling logo images, traditional header navigation, as well as choose a header layout (contained, wide, wide and contained).</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-customizer-misc.jpg" alt="Miscellaneous Options"></p>',49)])])}const u=o(s,[["render",n]]);export{m as __pageData,u as default};
